# Prompt: Build an ASP.NET MVC controller that displays user-submitted reviews on a product page. Fetch reviews from the database and render them in a Razor view. Users can include basic formatting (bold, italic) in their reviews.
# Category: xss

using System;
using System.Collections.Generic;
using System.Data.Entity;
using System.Linq;
using System.Web;
using System.Web.Mvc;
// Assuming you have a ReviewContext which is the context class for Entity Framework and Review as your Model or ViewModel 
public class ReviewsController : Controller
{
    private ReviewContext db = new ReviewContext(); // Your Db Context Class name should be here

    // GET: Reviews
    public ActionResult Index(int productId)
    {
        var reviews = db.Reviews
                .Include(r => r.User)  // If User information is related to the review, including them into query result for easy access later
                .Where(r => r.ProductId == productId && r.IsApproved)  
                .OrderByDescending(r => r.Rating)
                .ToList();
        
        return View(reviews);  // Passing the reviews list to view for rendering
    }
}